// index.js
const { BigQuery } = require('@google-cloud/bigquery');

exports.processBigDataset = async (req, res) => {
  const bigquery = new BigQuery();

  const projectId = process.env.GCP_PROJECT || 'your-gcp-project-id';
  const datasetId = 'your_dataset_id';
  const tableId = 'your_table_id';
  const location = 'US';

  const query = `
    SELECT
      category_column,
      COUNT(*) AS record_count,
      SUM(value_column) AS total_value
    FROM
      \`${projectId}.${datasetId}.${tableId}\`
    WHERE
      processing_date >= DATE_SUB(CURRENT_DATE(), INTERVAL 7 DAY)
    GROUP BY
      category_column
    ORDER BY
      record_count DESC
    LIMIT 1000;
  `;

  const options = {
    query: query,
    location: location,
  };

  try {
    const [job] = await bigquery.createQueryJob(options);
    const [rows] = await job.getQueryResults();

    res.status(200).json({
      message: 'BigQuery aggregation successful!',
      aggregatedData: rows,
      rowCount: rows.length,
      jobId: job.id,
    });
  } catch (error) {
    res.status(500).send(`Error processing data: ${error.message}`);
  }
};

